<?php
namespace App\Console\Commands;use App\Models\Document;use App\Models\DocumentAuditLog;use Illuminate\Console\Command;
class MarkExpiredDocuments extends Command{protected $signature='documents:mark-expired'; protected $description='Mark expired documents'; public function handle(){ $count=0; Document::whereDate('expiry_date','<',now()->toDateString())->where('status','!=','archived')->where('status','!=','expired')->chunkById(200,function($docs) use (&$count){foreach($docs as $d){$old=$d->status;$d->update(['status'=>'expired']);DocumentAuditLog::create(['document_id'=>$d->id,'business_id'=>$d->business_id,'action'=>'expired_by_system','old_values'=>['status'=>$old],'new_values'=>['status'=>'expired'],'performed_at'=>now()]);$count++;}}); $this->info("updated=$count"); return self::SUCCESS; }}
